// Collect all 5 articles into ONE prompt.
// We only want a single Groq API call — no loops, no per-item requests.

const items = $input.all();

const articleList = items
  .map((item, i) => {
    const title   = item.json.title           || 'Untitled';
    const link    = item.json.link            || '';
    const snippet = (item.json.contentSnippet || item.json.content || '').slice(0, 400);
    return `[${i + 1}] ${title}\n    Link: ${link}\n    ${snippet}`;
  })
  .join('\n\n');

const userMessage =
  `You are a sharp tech newsletter editor.\n` +
  `Below are ${items.length} articles from Hacker News.\n` +
  `Write a clean daily digest: for each article give it a bold title line,` +
  ` then 2-3 sentences on why it matters. Keep the whole digest under 400 words.\n\n` +
  articleList;

// Build the full Groq request body here so the HTTP node stays static.
const requestBody = JSON.stringify({
  model: 'llama-3.1-8b-instant',
  messages: [
    {
      role: 'system',
      content: 'You write concise, insightful tech digests. No fluff, no markdown headers — just clear paragraphs.'
    },
    {
      role: 'user',
      content: userMessage
    }
  ],
  max_tokens: 1024,
  temperature: 0.7
});

return [{ json: { requestBody, count: items.length } }];

// Parse Groq response and wrap it in a clean output object.
const response = $input.first().json;

if (!response.choices || !response.choices[0]) {
  throw new Error('Groq returned no choices. Raw response: ' + JSON.stringify(response));
}

const digest = response.choices[0].message.content.trim();

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    title:       `HN Digest — ${today}`,
    digest,
    tokens_used: response.usage?.total_tokens ?? 'unknown',
    generated_at: new Date().toISOString()
  }
}];
